CREATE TRIGGER [Global].[Plant_History]ON [Global].[Plant]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.PlantId IS NOT NULL AND d.PlantId IS NULL THEN 'I' 		WHEN i.PlantId IS NOT NULL AND d.PlantId IS NOT NULL THEN 'U' 		WHEN i.PlantId IS NULL AND d.PlantId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.PlantId = d.PlantId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Plant([PlantId], [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PlantId], [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Plant([PlantId], [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [PlantId], [SiteId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND